      const c3 = new PIXI.Graphics().circle(8, -12, 12 * scale).fill({ color: 0x40916c, alpha: 0.9 });
      t.addChild(trunk, c1, c2, c3);
      t.x = x; t.y = y;
      app.stage.addChild(t);
